            }
            if (do_update) {
                int p = line_pos[j];
                if (p < 0) p = 0;
                if (p < rows) {
                    int chosen = rand_printable();
                    if (matrix[p][j] != ' ') matrix[p][j] = chosen;
                }
                line_pos[j]++;
                if (line_pos[j] >= rows + length[j] + spaces[j]) {
                    line_pos[j] = 0;
                    length[j] = (rand() % (rows > 3 ? rows - 3 : 1)) + 3;
                    spaces[j] = (rand() % rows) + 1;
                }

